#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        if(N==3){
            printf("3 2 1\n");
            continue;
        }
        int *perm = (int*)malloc(N * sizeof(int));
        int cur = 1;
        // positions with weight 3: indices 2 .. N-3 (0‑based)
        for(int i=2; i<=N-3; ++i){
            perm[i] = cur++;
        }
        // weight 2 positions
        perm[1] = cur++;
        perm[N-2] = cur++;
        // weight 1 positions (ends)
        perm[0] = cur++;
        perm[N-1] = cur;
        for(int i=0;i<N;++i){
            if(i) printf(" ");
            printf("%d", perm[i]);
        }
        printf("\n");
        free(perm);
    }
    return 0;
}

